; ワイルド・ブルのアジト

name = ワイルドブルのアジト２Ｆ
insideName = ２Ｆ
lower = ワイルドブルのアジト１Ｆ
showAllArea = true
level = 10
bgm = hideout
margin = 1
shadow = dark
sky = black
roof = wood
blank = rock

; 各パーツ
━ = plaster
　 = wood
／ = door
∫ = pick
︻ = panel
㊦ = ladderd
⑻ = br_luc
⑼ = barrel
⑽ = barrel
Ⓐ = warp

; 移動ポイント
(A) = map:サファイアシティ, enter:公園

; 宝箱
box[1] = 爆弾,金貨（特大）,金貨（大）,金貨（大）,金貨（大）,金貨（小）,金貨（小）
box[2] = 鍵付き宝箱,魔法の錠前,魔法の錠前,精力剤,フェロモンの粉

[map]
